import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Empty / processing fee
  it.todo("empty item list — premium 5 G (only processing fee)");

  // Base premiums for main items (no modifiers, 0 years, single item)
  it.todo("single sword — base premium 100 G + 10 G first insurance + 5 G fee = 115 G");
  it.todo("single amulet — base premium 60 G + 6 G first insurance + 5 G fee = 71 G");
  it.todo("single staff — base premium 80 G + 8 G first insurance + 5 G fee = 93 G");
  it.todo("single potion — base premium 40 G + 4 G first insurance + 5 G fee = 49 G");

  // Components
  it.todo("single rune — base premium 25 G + first insurance and fee");
  it.todo("2 runes — base premium 50 G (no block)");
  it.todo("3 runes — base premium 60 G (building block applies)");
  it.todo("4 runes — base premium 100 G (no block — block requires exactly 3)");
  it.todo("7 runes — base premium 175 G (no block — not exactly 3)");

  // Alike components clarification (❓ alike means same type)
  it.todo("2 runes + 1 moonstone — base premium 75 G (no block: different types)");
  it.todo("3 runes + 3 moonstones — base premium 120 G (two separate blocks)");

  // Item-specific modifiers (in isolation)
  it.todo("cursed sword adds 50% risk surcharge (50 G to sword)");
  it.todo("highly enchanted sword (enchantment 5) adds 30% surcharge");
  it.todo("enchantment 4 does not trigger high-enchantment surcharge");
  it.todo("cursed AND highly enchanted sword stacks both surcharges");

  // Policy-wide modifiers
  it.todo("long-standing customer (≥ 2 years) gets 20% loyalty discount");
  it.todo("customer with exactly 2 years gets loyalty discount");
  it.todo("first insurance adds 10% initial assessment surcharge per item");
  it.todo("follow-up contract gets 15% discount on the policy");

  // Modifier scope (❓ cursed surcharge applies only to cursed item)
  it.todo("multi-item policy: cursed sword + plain amulet — premium with cursed surcharge applies to sword's base only");

  // Integration examples from spec
  it.todo("newcomer with cursed sword (enchantment 3) — 165 G");
  it.todo("long-standing customer's second contract: cursed sword enchantment 7 — 160 G");

  // Rounding
  it.todo("premium that yields 197.5 G — rounded up to 198 G");

  // Claim — standard reimbursement
  it.todo("regular sword (steel, enchantment 3), damage 500 G — payout 400 G");
  it.todo("damage to a rune (insurance value 250 G), damage 200 G — payout 100 G");

  // Claim — deductible per damage event
  it.todo("dragon attack damages sword (500 G) and amulet (300 G) — payout 600 G (deductible per item)");

  // Claim — high enchantment clause
  it.todo("steel sword enchantment 9, damage 1000 G — payout 400 G (50% then deductible)");

  // Claim — dragon material clause
  it.todo("dragon-material sword enchantment 5, damage 800 G — payout 700 G (full minus deductible)");

  // Claim — both clauses apply, 50% wins
  it.todo("dragon-material sword enchantment 9, damage 1000 G — payout 400 G (50% wins, then deductible)");
  it.todo("dragon-material sword enchantment exactly 8, damage 1000 G — payout 400 G (high-enchantment wins)");

  // Claim — cap exhaustion
  it.todo("sword and amulet policy — insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword — cap 2000 G (based on unmodified insurance value)");
  it.todo("sword + 3 runes — insurance sum 1750 G (block does not affect insurance sum)");
  it.todo("two successive claims of 1500 G on a sword — first payout 1400 G remaining 600 G, second payout 600 G remaining 0 G");

  // Multiple items of same type
  it.todo("policy with two swords — insurance sum 2000 G");
  it.todo("two swords damaged in dragon attack — each entry has its own deductible");
  it.todo("damages contain more entries of a type than insured — CLI exits non-zero");

  // Payout rounding (in MHPCO's favor: down)
  it.todo("payout that yields 350.5 G — rounded down to 350 G");

  // Edge cases — error handling
  it.todo("quote with unknown item type — CLI exits non-zero, error to stderr");
  it.todo("claim references item not part of policy — CLI exits non-zero");
  it.todo("claim with negative damage amount — CLI exits non-zero");

  // Multi-step scenarios
  it.todo("follow-up contracts: first quote no follow-up discount, second quote has follow-up discount");
});

