interface Item {
  type: string;
}

interface QuoteStep {
  op: "quote";
  items: Item[];
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
}

interface QuoteResult {
  premium: number;
}

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

const itemPremium = (item: Item): number => {
  const base = BASE_PREMIUM[item.type];
  return base + base * FIRST_INSURANCE_RATE;
};

const quoteStep = (step: QuoteStep): QuoteResult => {
  const itemsTotal = step.items.reduce((sum, item) => sum + itemPremium(item), 0);
  return { premium: itemsTotal + PROCESSING_FEE };
};

export const processScenario = (scenario: Scenario): { results: QuoteResult[] } => {
  const results = scenario.steps.map(quoteStep);
  return { results };
};

