27	const LOYALTY_RATE = 0.2;
28	const LOYALTY_THRESHOLD_YEARS = 2;
29	const CURSED_RATE = 0.5;
30	const HIGH_ENCHANTMENT_RATE = 0.3;
31	const HIGH_ENCHANTMENT_THRESHOLD = 5;
32	const BLOCK_SIZE = 3;
33	const BLOCK_BASE_PREMIUM = 60;
34	
35	const BASE_PREMIUM: Record<string, number> = {
36	  sword: 100,
37	  amulet: 60,
38	  staff: 80,
39	  potion: 40,
40	  rune: 25,
41	  moonstone: 25,
42	};
43	
44	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
45	
46	const isBuildingBlock = (type: string, count: number): boolean =>
47	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;
48	
49	const groupBasePremium = (type: string, count: number): number =>
50	  isBuildingBlock(type, count) ? BLOCK_BASE_PREMIUM : count * BASE_PREMIUM[type];
51	
52	const countByType = (items: Item[]): Map<string, number> =>
53	  items.reduce(
54	    (counts, item) => counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
55	    new Map<string, number>(),
56	  );
57	
58	const policyBase = (items: Item[]): number =>
59	  Array.from(countByType(items)).reduce(
60	    (total, [type, count]) => total + groupBasePremium(type, count),
61	    0,
62	  );
63	
64	const SURCHARGE_RATES: ReadonlyArray<(item: Item) => number> = [
65	  (item) => (item.cursed ? CURSED_RATE : 0),
66	  (item) => ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? HIGH_ENCHANTMENT_RATE : 0),
67	];
68	
69	const itemSurcharges = (item: Item): number => {
70	  const itemBase = BASE_PREMIUM[item.type];
71	  const totalRate = SURCHARGE_RATES.reduce((sum, rate) => sum + rate(item), 0);
72	  return itemBase * totalRate;
73	};
74	
75	const policySurcharges = (items: Item[]): number =>
76	  items.reduce((sum, item) => sum + itemSurcharges(item), 0);
77	
78	const firstInsuranceSurcharge = (base: number): number => base * FIRST_INSURANCE_RATE;
79	
80	const loyaltyDiscount = (customer: Customer, base: number): number =>
81	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? base * LOYALTY_RATE : 0;
82	
83	const quoteStep = (customer: Customer, { items }: QuoteStep): QuoteResult => {
84	  const base = policyBase(items);
85	  const additions = policySurcharges(items) + firstInsuranceSurcharge(base) + PROCESSING_FEE;
86	  const deductions = loyaltyDiscount(customer, base);
87	  return { premium: Math.ceil(base + additions - deductions) };
88	};
89	
90	export const processScenario = (scenario: Scenario): { results: QuoteResult[] } => {
91	  const results = scenario.steps.map((step) => quoteStep(scenario.customer, step));
92	  return { results };
93	};
