  it("multi-item policy: cursed sword + plain amulet — 231 G (cursed surcharge 50 G on sword only)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote",
        items: [{ type: "sword", cursed: true }, { type: "amulet" }],
